import { ref } from 'vue'

export const nom = ref('')
export const cognoms = ref('')
export const dni = ref('')
export const skills = ref([])
export const docs = ref(false)
export const professors = ref([])
export const editIndex = ref(null)

export function addProfessor () {
  const professorData = {
    nom: nom.value,
    cognoms: cognoms.value,
    dni: dni.value,
    skills: [...skills.value],
    docs: docs.value
  }

  if (editIndex.value === null) {
    professors.value.push(professorData)
  } else {
    professors.value[editIndex.value] = professorData
    editIndex.value = null
  }

  reiniciarFormulari()
}

export function editarElProfessor (index) {
  const p = professors.value[index]
  nom.value = p.nom
  cognoms.value = p.cognoms
  dni.value = p.dni
  skills.value = [...p.skills]
  docs.value = p.docs
  editIndex.value = index
}

export function esborrarProfessor (index) {
  professors.value.splice(index, 1)
}

export function reiniciarFormulari () {
  nom.value = ''
  cognoms.value = ''
  dni.value = ''
  skills.value = []
  docs.value = false
}
